SELECT 
FROM core_field_catalog
WHERE stable_key = #{stableKey}
  AND core_object_type = #{coreObjectType}

SELECT 
FROM core_field_catalog
WHERE core_object_type = #{coreObjectType}

    AND id > #{lastId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

ORDER BY id ASC
LIMIT #{size}

SELECT 
FROM core_field_catalog
WHERE source = #{source}

    AND id > #{lastId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

ORDER BY id ASC
LIMIT #{size}

SELECT 
FROM core_field_catalog


        id > #{lastId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


ORDER BY id ASC
LIMIT #{size}
